// Booked dates (YYYY-MM-DD format)
export const BOOKED_DATES = new Set([
  '2026-06-02', '2026-06-03', '2026-06-10', '2026-06-11',
  '2026-06-12', '2026-06-13', '2026-06-17', '2026-06-24',
  '2026-07-07', '2026-07-14', '2026-07-24', '2026-07-25',
]);

// Philippine public holidays 2026
export const HOLIDAYS = new Set([
  '2026-06-12', // Independence Day
  '2026-08-21', // Ninoy Aquino Day
  '2026-08-31', // National Heroes Day
  '2026-11-01', // All Saints Day
  '2026-11-02', // All Souls Day
  '2026-11-30', // Bonifacio Day
  '2026-12-08', // Immaculate Conception
  '2026-12-25', // Christmas Day
  '2026-12-30', // Rizal Day
  '2026-12-31', // New Year's Eve
]);

export const ROOM_TYPES = [
  {
    id: 'sakura-suite',
    name: 'Sakura Suite',
    price: 8500,
    maxGuests: 2,
    description: 'Cherry blossom garden view, king bed, soaking tub',
    icon: '🌸',
  },
  {
    id: 'bamboo-deluxe',
    name: 'Bamboo Deluxe',
    price: 6200,
    maxGuests: 3,
    description: 'Forest view, queen bed, private balcony',
    icon: '🎋',
  },
  {
    id: 'tatami-premier',
    name: 'Tatami Premier',
    price: 9800,
    maxGuests: 4,
    description: 'Traditional tatami floor, mountain view, family room',
    icon: '🏯',
  },
  {
    id: 'ryokan-villa',
    name: 'Ryokan Villa',
    price: 15000,
    maxGuests: 6,
    description: 'Private villa, onsen-style bath, full kitchen',
    icon: '⛩️',
  },
];

export const isWeekend = (date) => {
  const d = new Date(date);
  const day = d.getDay();
  return day === 0 || day === 6;
};

export const isHoliday = (dateStr) => HOLIDAYS.has(dateStr);
export const isBooked = (dateStr) => BOOKED_DATES.has(dateStr);

export const formatDate = (dateStr) => {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-PH', {
    weekday: 'short',
    month: 'long',
    day: 'numeric',
    year: 'numeric',
  });
};

export const diffDays = (start, end) => {
  if (!start || !end) return 0;
  const s = new Date(start + 'T00:00:00');
  const e = new Date(end + 'T00:00:00');
  return Math.round((e - s) / (1000 * 60 * 60 * 24));
};

export const toDateStr = (year, month, day) => {
  return `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
};
